"use strict";const e=require("../common/vendor.js"),n=require("./api.js");exports.getToken=()=>e.index.getStorageSync("token")||"",exports.getUserInfo=()=>{try{const n=e.index.getStorageSync("userInfo");return n?JSON.parse(n):null}catch{return null}},exports.login=()=>new Promise((o,r)=>{e.index.login({provider:"weixin",success(t){t.code?n.post("/auth/wechat-login",{code:t.code}).then(n=>{e.index.setStorageSync("token",n.token),e.index.setStorageSync("userInfo",JSON.stringify(n.user)),o(n.user)}).catch(r):r(new Error("微信登录失败"))},fail:r})}),exports.logout=()=>{e.index.removeStorageSync("token"),e.index.removeStorageSync("userInfo")};
